1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
7	const CURSE_SURCHARGE_PERCENT = 50;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
10	const LOYALTY_THRESHOLD_YEARS = 2;
11	const LOYALTY_DISCOUNT_PERCENT = 20;
12	const COMPONENT_BLOCK_SIZE = 3;
13	const COMPONENT_BLOCK_PREMIUM = 60;
14	
15	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	
26	const groupBaseAmount = (type: string, count: number): number => {
27	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
28	    return COMPONENT_BLOCK_PREMIUM;
29	  }
30	  return count * BASE_PREMIUM_BY_TYPE[type];
31	};
32	
33	const countByType = (items: Item[]): Map<string, number> =>
34	  items.reduce(
35	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
36	    new Map<string, number>(),
37	  );
38	
39	const basePremium = (items: Item[]): number =>
40	  Array.from(countByType(items)).reduce(
41	    (total, [type, count]) => total + groupBaseAmount(type, count),
42	    0,
43	  );
44	
45	const percentOf = (amount: number, percent: number): number =>
46	  (amount * percent) / 100;
47	
48	const percentOfItemBase = (item: Item, percent: number): number =>
49	  percentOf(BASE_PREMIUM_BY_TYPE[item.type], percent);
50	
51	const firstInsuranceSurcharge = (base: number): number =>
52	  Math.ceil(percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT));
53	
54	const curseSurcharge = (item: Item): number =>
55	  item.cursed ? percentOfItemBase(item, CURSE_SURCHARGE_PERCENT) : 0;
56	
57	const highEnchantmentSurcharge = (item: Item): number =>
58	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
59	    ? percentOfItemBase(item, HIGH_ENCHANTMENT_SURCHARGE_PERCENT)
60	    : 0;
61	
62	const itemSurcharges = (items: Item[]): number =>
63	  items.reduce((sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item), 0);
64	
65	type Customer = { yearsWithMHPCO: number };
66	
67	const loyaltyDiscount = (base: number, customer: Customer): number =>
68	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
69	    ? percentOf(base, LOYALTY_DISCOUNT_PERCENT)
70	    : 0;
71	
72	const quotePremium = (items: Item[], customer: Customer): number => {
73	  const base = basePremium(items);
74	  return (
75	    base
76	    + itemSurcharges(items)
77	    - loyaltyDiscount(base, customer)
78	    + firstInsuranceSurcharge(base)
79	    + PROCESSING_FEE
80	  );
81	};
82	
83	const executeStep = (customer: Customer) => ({ items }: Step) => ({
84	  premium: quotePremium(items, customer),
85	});
86	
87	export const run = (input: unknown): unknown => {
88	  const { customer, steps } = input as Input;
89	  return { results: steps.map(executeStep(customer)) };
90	};
